import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { AssetType, EmailOptions, LPOptions, VSLOptions, AdOptions, GlobalSettings, BriefInputs, BigIdeaResult } from "./types";

export async function buildFullStrategicBrief(inputs: BriefInputs, global: GlobalSettings): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
  const response = await ai.models.generateContent({
    model: global.model,
    contents: `Generate a strategy brief based on these inputs: ${JSON.stringify(inputs)}. 
    IMPORTANT: If a Big Idea is provided, ensure the entire strategy revolves around it. 
    Big Idea: ${inputs.bigIdea || "None provided yet."}
    Focus on the psychological levers and the unique mechanism of the Big Idea.`,
    config: { systemInstruction: "You are an Elite Copywriting Strategist." }
  });
  return response.text || "";
}

export async function developBigIdea(inputs: BriefInputs, global: GlobalSettings): Promise<BigIdeaResult> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

  // Phase 1 & 2: Pains and "Why"
  const discoveryResponse = await ai.models.generateContent({
    model: global.model,
    contents: `Based on this business: ${JSON.stringify(inputs)}, 
    1. Identify the top 5 deep-seated emotional pain points.
    2. Formulate a core problem statement and rephrase it as a provocative 'Why' question that challenges industry norms.`,
    config: { 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          pains: { type: Type.ARRAY, items: { type: Type.STRING } },
          coreWhy: { type: Type.STRING }
        },
        required: ["pains", "coreWhy"]
      }
    }
  });

  const baseResult = JSON.parse(discoveryResponse.text || "{}");

  // Phase 3 & 4: Search for Hidden Ideas
  const searchPrompt = `Search for breakthroughs, surprising discoveries, or contrarian studies related to: ${baseResult.coreWhy}. 
  Find ideas that are:
  1. HIDDEN: Counter-intuitive, high curiosity.
  2. EMERGING: New trends with momentum.
  3. KNOWN: Industry standards that need a new angle.
  Categorize 3 distinct research findings.`;

  const searchResponse = await ai.models.generateContent({
    model: global.model,
    contents: searchPrompt,
    config: {
      tools: [{ googleSearch: {} }],
    }
  });

  // Final Synthesis
  const synthesisPrompt = `Given the research findings: ${searchResponse.text}
  And the core 'Why': ${baseResult.coreWhy}
  Create a single, concise "Big Idea" statement that positions the offer as the inevitable solution. 
  It must be emotionally compelling, contrarian, and easily provable.
  Also, return a structured list of the discoveries found in the research.`;

  const finalResponse = await ai.models.generateContent({
    model: global.model,
    contents: synthesisPrompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          finalStatement: { type: Type.STRING },
          discoveries: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                type: { type: Type.STRING, description: "hidden, emerging, or known" },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                momentum: { type: Type.NUMBER },
                virality: { type: Type.NUMBER }
              },
              required: ["id", "type", "title", "description", "momentum", "virality"]
            }
          }
        },
        required: ["finalStatement", "discoveries"]
      }
    }
  });

  const finalResult = JSON.parse(finalResponse.text || "{}");

  return {
    ...baseResult,
    discoveries: finalResult.discoveries,
    finalStatement: finalResult.finalStatement
  };
}

export async function analyzeReferenceAsset(
  type: 'image' | 'url',
  data: string,
  global: GlobalSettings
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
  let parts: any[] = [];
  if (type === 'image') {
    parts = [{ text: "Analyze this landing page image. Extract its: 1. Value Proposition, 2. Hook style, 3. Visual sections/flow, 4. Specific psychological triggers used, 5. CTA placement and wording." }, { inlineData: { mimeType: "image/png", data: data.split(',')[1] } }];
  } else {
    parts = [{ text: `Using Google Search, visit and analyze the landing page at ${data}. Extract its: 1. Value Proposition, 2. Hook style, 3. Structural components, 4. Triggers, 5. CTA style.` }];
  }
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts },
    config: { tools: type === 'url' ? [{ googleSearch: {} }] : undefined }
  });
  return response.text || "Analysis failed.";
}

export async function recommendLPSettings(brief: string, global: GlobalSettings): Promise<{ structureType: string; reason: string }> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
  const response = await ai.models.generateContent({
    model: global.model,
    contents: `Based on this brief, recommend the best Landing Page Framework: ${brief}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: { structureType: { type: Type.STRING }, reason: { type: Type.STRING } },
        required: ["structureType", "reason"]
      }
    }
  });
  try { return JSON.parse(response.text || "{}"); } catch { return { structureType: 'SaaS Acceleration Matrix', reason: 'Logical default.' }; }
}

