export async function generateMarketingCopy(
  brief: string,
  assetType: AssetType,
  options: EmailOptions | LPOptions | VSLOptions | AdOptions,
  global: GlobalSettings,
  isRefinement: boolean = false,
  refinementFeedback: string = "",
  refinementType: 'Fix' | 'Remake' = 'Remake',
  previousContent: string = ""
): Promise<{ text: string; sources?: any[] }> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
  let assetSpecificPrompt = "";
  if (assetType === 'Email') {
    const opt = options as EmailOptions;
    assetSpecificPrompt = `TASK: Write Email #${opt.emailNumber}. Sequence: ${opt.sequenceType}. Structure: ${opt.structure}. Sign-off: ${opt.userName}.`;
  } else if (assetType === 'Landing Page') {
    const opt = options as LPOptions;
    assetSpecificPrompt = `TASK: Write a highly persuasive "${opt.pageType}". Goal: ${opt.pageGoal}. Framework: ${opt.structureType}. Style: ${opt.copyStyle}. Strategy: ${opt.focusStrategy}. Blocks: ${opt.includeBlocks.join(', ')}. CTA: ${opt.ctaText}.`;
  } else if (assetType === 'VSL') {
    const opt = options as VSLOptions;
    assetSpecificPrompt = `ROLE: World-Class VSL Copywriter. GOAL: ${opt.vslGoal}. FRAMEWORK: ${opt.framework}. HOOK: ${opt.hookType}. LENGTH: ${opt.scriptLength}.`;
  } else if (assetType === 'Ads') {
    const opt = options as AdOptions;
    assetSpecificPrompt = `ROLE: Expert Ad Copywriter. PLATFORM: ${opt.platform}. FRAMEWORK: ${opt.framework}. GOAL: ${opt.adGoal}. HOOK: ${opt.hookType}. VARIATIONS: ${opt.variations}.`;
  }
  const response: GenerateContentResponse = await ai.models.generateContent({
    model: global.model,
    contents: `${isRefinement ? "REFINEMENT: " + refinementFeedback : "GENERATE NEW COPY."} BRIEF: ${brief} ${assetSpecificPrompt}`,
    config: {
      systemInstruction: "You are an Elite Direct Response Copywriter.",
      tools: global.useGoogleSearch ? [{ googleSearch: {} }] : undefined,
    },
  });
  return { text: response.text || "Failed to generate content." };
}

export async function autoFillContext(rawText: string, global: GlobalSettings): Promise<Partial<BriefInputs>> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
  const response = await ai.models.generateContent({
    model: global.model,
    contents: `Extract businessName, industry, targetAudience, productDescription, primaryUSP, painPoints from: "${rawText}"`,
    config: { responseMimeType: "application/json" }
  });
  try { return JSON.parse(response.text || "{}"); } catch { return {}; }
}

