    </div>
  </div>
);

const NavTab = ({ label, icon: Icon, active, onClick, tooltip }: { label: string, icon: any, active: boolean, onClick: () => void, tooltip: string }) => (
  <Tooltip text={tooltip}>
    <button onClick={onClick} className={`flex items-center gap-2 px-6 py-4 transition-all duration-300 border-b-2 font-bold text-xs uppercase tracking-widest ${active ? 'border-indigo-500 text-white bg-indigo-500/5' : 'border-transparent text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}`}>
      <Icon size={16} className={active ? 'text-indigo-400' : 'text-slate-600'} />
      {label}
    </button>
  </Tooltip>
);

const SmartLoadingButton = ({ onClick, isLoading, loadingPhrases, label, icon: Icon, disabled, variant = 'primary', className = "" }: { onClick: () => void, isLoading: boolean, loadingPhrases: string[], label: string, icon: any, disabled?: boolean, variant?: 'primary' | 'ghost' | 'secondary', className?: string }) => {
  const [phraseIdx, setPhraseIdx] = useState(0);
  useEffect(() => {
    if (!isLoading) return;
    const interval = setInterval(() => setPhraseIdx(p => (p + 1) % loadingPhrases.length), 2000);
    return () => clearInterval(interval);
  }, [isLoading, loadingPhrases]);
  return (
    <button onClick={onClick} disabled={disabled || isLoading} className={`relative overflow-hidden transition-all duration-300 active:scale-[0.98] flex items-center justify-center gap-2 ${variant === 'primary' ? 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg disabled:bg-slate-800' : variant === 'ghost' ? 'bg-indigo-500/10 border border-indigo-500/20 text-indigo-400 hover:bg-indigo-500/20' : 'bg-slate-800/40 border border-slate-700/60 text-slate-400 hover:text-white'} ${className}`}>
      {isLoading ? <><Loader2 className="animate-spin" size={16} /> <span className="italic">{loadingPhrases[phraseIdx]}</span></> : <><Icon size={16} /> <span>{label}</span></>}
    </button>
  );
};

