    // Extract the header (first line)
    const header = lines[0].trim();
    // Extract the content (rest of the lines)
    const content = lines.slice(1).join('\n').trim();

    // Check if header is already used
    if (existingSummary.includes(header.slice(2, -2))) {
        // Return existing summary if header is duplicate
        return existingSummary;
    }

    // Process the new thought
