  data.promise.transformation = getVal(/THE TRANSFORMATION:\s*(.*)/i);
  data.promise.whyShortfall = getVal(/WHY SHORTFALL:\s*(.*)/i);
  data.promise.commonFrustrations = getVal(/COMMON FRUSTRATIONS:\s*(.*)/i);
